mapper.select:
SELECT tf.name FROM field_values fv JOIN task_fields tf ON fv.field_id = tf.id
AND fv.tasks_id = #{tasksId}
ORDER BY tf.sort

SELECT fv.tasks_id,
MAX(CASE WHEN tf.name = #{field} THEN fv.value END) AS ${field}
FROM field_values fv JOIN task_fields tf ON fv.field_id = tf.id
AND fv.tasks_id = #{tasksId}
GROUP BY fv.tasks_id

SELECT su.id as userId, su.user_name as userName FROM sys_user su WHERE su.id IN ( SELECT DISTINCT user_id FROM ( SELECT assignee as user_id FROM task WHERE assignee IS NOT NULL and is_deleted = 0
AND project_id IN
#{projectId}
UNION SELECT assigner as user_id FROM task WHERE assigner IS NOT NULL AND is_deleted = 0
AND project_id IN
#{projectId}
) members WHERE user_id IS NOT NULL ) AND su.status = 0 AND su.del_flag = 0 ORDER BY su.id

SELECT task_title as taskTitle, status,priority FROM task WHERE is_deleted = '0'
AND project_id IN
#{projectId}
AND 1 = 0
and (assigner = #{userId} or assignee = #{userId}) order by id desc limit 10;

SELECT COALESCE( SUM(CASE WHEN t.status = '1' THEN 1 ELSE 0 END)) AS pending, COALESCE( SUM(CASE WHEN t.status = '2' THEN 1 ELSE 0 END)) AS inProgress, COALESCE( SUM(CASE WHEN t.status = '3' THEN 1 ELSE 0 END)) AS completed, COALESCE( SUM(CASE WHEN t.status = '4' THEN 1 ELSE 0 END)) AS canceled, COALESCE( SUM(CASE WHEN t.status = '5' THEN 1 ELSE 0 END)) AS blocked, COALESCE( SUM(CASE WHEN t.due_date IS NOT NULL AND NOW() > t.due_date AND t.status NOT IN ('3', '4') THEN 1 ELSE 0 END)) AS overdue FROM task t LEFT JOIN project p ON t.project_id = p.id WHERE t.is_deleted = '0'
AND t.due_date >= #{startTime}
AND t.start_time <= #{dueTime}
AND t.project_id in ( -- 1. 递归查询：获取当前用户拥有的所有项目（包括子项目） WITH RECURSIVE project_tree AS ( -- 基础查询：当前用户拥有的直属项目 SELECT id FROM project WHERE id= #{projectId} UNION ALL -- 递归部分：查找子项目 SELECT p.id FROM project p INNER JOIN project_tree pt ON p.parent_id = pt.id ) -- 2. 检查任务项目是否在该树中 SELECT * FROM project_tree)
AND (t.assignee = #{loginIdAsString} OR t.assigner = #{loginIdAsString})

SELECT DATE(t.actual_finish_time) AS date, COUNT(*) AS count FROM task t WHERE t.is_deleted = '0' AND t.status = '3' -- 已完成 AND t.actual_finish_time IS NOT NULL
AND t.actual_finish_time >= #{startTime}
AND t.actual_finish_time <= #{dueTime}
AND t.project_id in ( -- 1. 递归查询：获取当前用户拥有的所有项目（包括子项目） WITH RECURSIVE project_tree AS ( -- 基础查询：当前用户拥有的直属项目 SELECT id FROM project WHERE id= #{projectId} UNION ALL -- 递归部分：查找子项目 SELECT p.id FROM project p INNER JOIN project_tree pt ON p.parent_id = pt.id ) -- 2. 检查任务项目是否在该树中 SELECT * FROM project_tree)
AND (t.assignee = #{loginIdAsString} OR t.assigner = #{loginIdAsString})
GROUP BY DATE(t.actual_finish_time) ORDER BY date ASC

SELECT DATE(t.create_time) AS date, COUNT(*) AS count FROM task t WHERE t.is_deleted = '0'
AND t.create_time >= #{startTime}
AND t.create_time <= #{dueTime}
AND t.project_id in ( -- 1. 递归查询：获取当前用户拥有的所有项目（包括子项目） WITH RECURSIVE project_tree AS ( -- 基础查询：当前用户拥有的直属项目 SELECT id FROM project WHERE id= #{projectId} UNION ALL -- 递归部分：查找子项目 SELECT p.id FROM project p INNER JOIN project_tree pt ON p.parent_id = pt.id ) -- 2. 检查任务项目是否在该树中 SELECT * FROM project_tree)
AND (t.assignee = #{loginIdAsString} OR t.assigner = #{loginIdAsString})
GROUP BY DATE(t.create_time) ORDER BY date ASC

WITH RECURSIVE date_range AS ( SELECT DATE(start_time) AS dt FROM task WHERE is_deleted = '0' AND id IN
#{id}
GROUP BY DATE(start_time) -- ✅ 使用 GROUP BY 替代 DISTINCT
UNION ALL
SELECT DATE_ADD(dt, INTERVAL 1 DAY) FROM date_range WHERE dt < ( SELECT MAX(DATE(due_date)) FROM task WHERE is_deleted = '0' AND id IN
#{id}
) ), task_daily_hours AS ( SELECT t.id, DATE(t.start_time) AS start_day, DATE(t.due_date) AS end_day, t.estimated_hours, DATEDIFF(t.due_date, t.start_time) + 1 AS total_days, t.estimated_hours / (DATEDIFF(t.due_date, t.start_time) + 1) AS daily_hours FROM task t WHERE is_deleted = '0' AND id IN
#{id}
), daily_distribution AS ( SELECT tdh.id, tdh.daily_hours, dr.dt AS daily_date FROM task_daily_hours tdh CROSS JOIN date_range dr WHERE dr.dt >= tdh.start_day AND dr.dt <= tdh.end_day ) SELECT dd.daily_date AS DATE, ROUND(SUM(dd.daily_hours), 2) AS hours FROM daily_distribution dd GROUP BY dd.daily_date ORDER BY dd.daily_date;

SELECT t.*
FROM task t
WHERE t.is_deleted = '0'

    AND t.due_date >= #{startTime}


    AND t.start_time <= #{dueTime}



    AND EXISTS (
    WITH RECURSIVE project_tree AS (
    SELECT id FROM project WHERE id = #{projectId}
    UNION ALL
    SELECT p.id FROM project p
    INNER JOIN project_tree pt ON p.parent_id = pt.id
    )
    SELECT 1 FROM project_tree pt
    WHERE pt.id = t.project_id
    )

        AND (t.assignee = #{loginIdAsString} OR t.assigner = #{loginIdAsString})
